SELECT option_name
FROM configuration_options
WHERE status = 'active';

SELECT group_name
FROM function_groups
WHERE group_name = 'Group A';

SELECT group_name
FROM function_groups
WHERE created_by = 1;

SELECT group_name
FROM function_groups
WHERE group_id = 1;

SELECT COUNT(*) AS protection_count
FROM configuration_logs
WHERE change_type IN ('protect', 'unprotect');

SELECT COUNT(*) AS total_protected_groups
FROM function_groups
WHERE is_protected = 1;

SELECT COUNT(DISTINCT option_id) AS total_unique_options
FROM configuration_logs
WHERE change_date >= DATE('now', '-30 days');

SELECT COUNT(version_id) AS current_version_count
FROM application_versions
WHERE is_current = 1;
